sqlMap.insert:
DROP TEMPORARY TABLE IF EXISTS temp_pm_project_real_product_line_from_sms; CREATE TEMPORARY TABLE IF NOT EXISTS temp_pm_project_real_product_line_from_sms ( KEY orderExecNumber(orderExecNumber), KEY orderExecSubNum(orderExecSubNum), KEY orderExecSubNum2(orderExecSubNum2) ) SELECT rl.* , CAST(CONCAT(LEFT(rl.`orderExecNumber`, 12), SUBSTR(rl.`orderExecNumber`, 14)) AS CHAR(255)) AS orderExecSubNum , CAST(CONCAT(LEFT(rl.`orderExecNumber`, 12), SUBSTR(rl.`orderExecNumber`, 15)) AS CHAR(255)) AS orderExecSubNum2 FROM pm_project_real_product_line_from_sms rl INNER JOIN (SELECT projectCode, MAX(orderExecNumber) AS orderExecNumber, SUBSTR(`orderExecNumber`, 14, 1) AS orderType FROM pm_project_real_product_line_from_sms GROUP BY projectCode, orderType) mrl ON rl.`projectCode` = mrl.projectCode AND rl.`orderExecNumber` = mrl.orderExecNumber;
DROP TEMPORARY TABLE IF EXISTS temp_pm_order_data_from_sap; CREATE TEMPORARY TABLE IF NOT EXISTS temp_pm_order_data_from_sap( KEY contractNo(contractNo), KEY orderExecNumber(orderExecNumber), KEY orderExecSubNum(orderExecSubNum) ) SELECT DISTINCT contractNo, orderExecNumber, CONCAT( LEFT(podfs.`orderExecNumber`, 12), SUBSTR(podfs.`orderExecNumber`, 14) ) AS orderExecSubNum FROM pm_order_data_from_sap podfs;
DROP TEMPORARY TABLE IF EXISTS temp_pm_order_data_from_sap_ignoreType; CREATE TEMPORARY TABLE IF NOT EXISTS temp_pm_order_data_from_sap_ignoreType ( KEY contractNo (contractNo), KEY orderExecSubNum (orderExecSubNum), KEY orderExecSubNum2 (orderExecSubNum2) ) SELECT DISTINCT contractNo, orderExecSubNum, CONCAT( LEFT(podfs.`orderExecNumber`, 12), SUBSTR(podfs.`orderExecNumber`, 15) ) AS orderExecSubNum2 FROM temp_pm_order_data_from_sap podfs ;
INSERT INTO pm_project_product_line_real SELECT NULL AS id, pph.`projectId`, podfs.`contractNo`, vrp.projectCode, vrp.orderExecNumber, vrp.productFirstName, vrp.productName, vrp.productSubCode, vrp.productSubModel, vrp.productSubName, vrp.num, vrp.memo FROM temp_pm_project_real_product_line_from_sms vrp INNER JOIN temp_pm_order_data_from_sap podfs ON vrp.orderExecNumber = podfs.orderExecNumber INNER JOIN pm_project_contract ppc ON ppc.`contractNo` = podfs.`contractNo` INNER JOIN pm_project_group_relationship ppgr ON ppc.`projectGroupCode` = ppgr.`projectGroupCode` INNER JOIN pm_project_header pph ON pph.`projectCode` = ppgr.`projectCode` ;
INSERT INTO pm_project_product_line_real SELECT NULL AS id, pph.`projectId`, podfs.`contractNo`, vrp.projectCode, vrp.orderExecNumber, vrp.productFirstName, vrp.productName, vrp.productSubCode, vrp.productSubModel, vrp.productSubName, vrp.num, vrp.memo FROM temp_pm_project_real_product_line_from_sms vrp INNER JOIN temp_pm_order_data_from_sap_ignoreType podfs ON vrp.`orderExecSubNum` = podfs.orderExecSubNum INNER JOIN pm_project_contract ppc ON ppc.`contractNo` = podfs.`contractNo` INNER JOIN pm_project_group_relationship ppgr ON ppc.`projectGroupCode` = ppgr.`projectGroupCode` INNER JOIN pm_project_header pph ON pph.`projectCode` = ppgr.`projectCode` WHERE NOT EXISTS (SELECT 1 FROM pm_order_data_from_sap po WHERE vrp.orderExecNumber = po.orderExecNumber) ;
INSERT INTO pm_project_product_line_real SELECT NULL AS id, pph.`projectId`, podfs.`contractNo`, vrp.projectCode, vrp.orderExecNumber, vrp.productFirstName, vrp.productName, vrp.productSubCode, vrp.productSubModel, vrp.productSubName, vrp.num, vrp.memo FROM temp_pm_project_real_product_line_from_sms vrp INNER JOIN (SELECT DISTINCT contractNo, orderExecSubNum2 FROM temp_pm_order_data_from_sap_ignoreType) podfs ON vrp.`orderExecSubNum2` = podfs.orderExecSubNum2 INNER JOIN pm_project_contract ppc ON ppc.`contractNo` = podfs.`contractNo` INNER JOIN pm_project_group_relationship ppgr ON ppc.`projectGroupCode` = ppgr.`projectGroupCode` INNER JOIN pm_project_header pph ON pph.`projectCode` = ppgr.`projectCode` WHERE NOT EXISTS (SELECT 1 FROM temp_pm_order_data_from_sap po WHERE vrp.orderExecSubNum = po.orderExecSubNum);
DROP TEMPORARY TABLE IF EXISTS temp_pm_project_real_product_line_from_sms; DROP TEMPORARY TABLE IF EXISTS temp_pm_order_data_from_sap; DROP TEMPORARY TABLE IF EXISTS temp_pm_order_data_from_sap_ignoreType;
